              comment_content_json:
                '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"ResearchHub Foundation is offering an incentive of $150 in ResearchCoin (RSC) for up to two high-quality, rigorous, and constructive peer reviews of this proposal."}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Requirements:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Verify identity and complete profile (including ORCID auth) on ResearchHub."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Submit your review within 14 days of the date this bounty was initiated."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Describe the relevance of your domain expertise to the manuscript."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Disclose AI use. Please refer to our "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://drive.google.com/file/d/1KihDvQze5rzi8xwleWfMNsdPbc6EF0t_/view","target":"_blank","rel":"noopener noreferrer","class":"tiptap-link text-blue-600 hover:underline"}}],"text":"AI Policy"},{"type":"text","text":" for additional details."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Disclose conflicts of interest."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Review Factors:"},{"type":"hardBreak"},{"type":"text","text":"“Overall Impact Score” and “Core Review Factors” are mandatory and should be scored from 1 (poor) to 5 (excellent). “Additional Review Requirements” are not scored but should be addressed as needed. Please refer to the "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.researchhub.com/researchhub-foundation/programs-and-initiatives/peer-review-program/peer-review-guidelines/funding-evaluation-guidelines","target":"_blank","rel":"noopener noreferrer","class":"tiptap-link text-blue-600 hover:underline"}}],"text":"Funding Evaluation Guidelines"},{"type":"text","text":" for details on how to evaluate proposals."}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Overall Impact (scored): Assess the proposal\'s novelty, rigor, reproducibility, and potential impact on the field. "}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Core Review Factors (scored):"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"underline"}],"text":"Importance (Significance & Innovation)"},{"type":"hardBreak"},{"type":"text","text":"Assess the strength of the hypothesis, the novelty of the work, the importance of the research question, and its potential to advance knowledge in the field."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"underline"}],"text":"Rigor & Feasibility (Approach, Team, Budget)"},{"type":"hardBreak"},{"type":"text","text":"Evaluate the study design, methodology, feasibility of the proposed timeline, qualifications of the research team, quality of the research environment, and appropriateness of the budget and its justification."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Additional Review Requirements (not scored):"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Confirm that appropriate human subject or animal protections are in place, if applicable."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"For resubmissions or revisions, verify that prior critiques have been adequately addressed."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check for adherence to open science principles, including availability of data, code, and protocols when possible."}]}]}]}]}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Editors will review and award up to 2 high-quality peer reviews within 1 week following the 14 day submission window. All decisions are final. For questions, please contact "},{"type":"text","marks":[{"type":"link","attrs":{"href":"mailto:editorial@researchhub.foundation","target":"_blank","rel":"noopener noreferrer nofollow","class":"text-blue-600 hover:text-blue-800 cursor-pointer relative group"}},{"type":"underline"}],"text":"editorial@researchhub.foundation"}]}]}',
