                  user: {
                    id: 39602,
                    last_name: 'Account',
                    first_name: 'Main',
                    is_verified: true,
                    created_date: '2023-06-05T19:43:38.239592Z',
                    updated_date: '2024-11-29T15:13:55.271981Z',
                  },
                  amount: '300',
